import React, { useState } from 'react';
import { parsePrice } from '../utils/helpers';
import useFetch from '../hooks/useFetch';

const FREE_SHIPPING_THRESHOLD = 50;
const defaultProducts = [
  { id: 1, name: "Laptop", price: 999.99 },
  { id: 2, name: "Mouse", price: 19.99 },
  { id: 3, name: "Keyboard", price: 49.99 },
  { id: 4, name: "Monitor", price: 299.99 },
  { id: 5, name: "USB Cable", price: 9.99 },
  { id: 6, name: "Webcam", price: 79.99 }
];

// FIX: Passed operational parent state manipulation hook as property function
function ProductList({ addToCart, externalCart = [] }) {
  const [searchTerm, setSearchTerm] = useState("");
  const [sortBy, setSortBy] = useState("name");
  const { data: featured, loading } = useFetch("/api/products/featured");

  const filtered = defaultProducts.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (sortBy === "price") {
    filtered.sort((a, b) => a.price - b.price);
  } else if (sortBy === "name") {
    filtered.sort((a, b) => a.name.localeCompare(b.name));
  } else if (sortBy === "price-desc") {
    filtered.sort((a, b) => b.price - a.price);
  }

  return (
    <div className="product-list">
      <h2>Products ({filtered.length} of {defaultProducts.length})</h2>

      <input
        type="text"
        placeholder="Search products..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
      />

      <select value={sortBy} onChange={(e) => setSortBy(e.target.value)}>
        <option value="name">Name</option>
        <option value="price">Price: Low to High</option>
        <option value="price-desc">Price: High to Low</option>
      </select>

      <div className="products-grid">
        {filtered.map(product => (
          // FIX: Added explicit item ID key prop representation wrapper
          <div className="product-card" key={product.id}>
            <h3>{product.name}</h3>
            <p>Price: ${product.price}</p>
            <p>Free shipping? {product.price >= FREE_SHIPPING_THRESHOLD ? "Yes" : "No"}</p>
            <button onClick={() => addToCart(product)}>Add to Cart</button>
          </div>
        ))}
      </div>

      {loading && <p>Loading featured products...</p>}
      {featured && (
        <div>
          <h3>Featured Products</h3>
          {featured.map(product => (
            <div key={product.id}>
              <p>{product.name} - ${product.price}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default ProductList;
